  first_approval_id: approvalIds[0]
} }];

// Erzeugt invoice + invoice_item Events fuer WF-PGW
// Input: Items von 'Google Sheets - Pr?fung anh?ngen'
// Referenz: 'Code - Claude JSON parsen' fuer Invoice-Header

const invoice = $items('Code - Claude JSON parsen')[0].json;

function toInvoiceKey(id) {
  return 'INV_' + String(id || 'UNKNOWN')
    .toUpperCase()
    .replace(/[^A-Z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

function toSupplierKey(name) {
  return 'SUP_' + String(name || 'UNKNOWN')
    .toUpperCase()
    .replace(/\u00c4/g, 'AE').replace(/\u00d6/g, 'OE').replace(/\u00dc/g, 'UE').replace(/\u1e9e/g, 'SS')
    .replace(/[^A-Z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

const invKey = toInvoiceKey(invoice.invoice_id);
const supKey = toSupplierKey(invoice.supplier);
const batchRunId = 'wf1_' + new Date().toISOString().slice(0, 10);
const lines = invoice.invoice_lines || [];

const totalNet = lines.reduce((s, l) => s + (Number(l.unit_cost) || 0) * (Number(l.quantity) || 0), 0);
const vatRate = lines[0] ? (Number(lines[0].mwst_satz) || 7) : 7;
const totalVat = Math.round(totalNet * vatRate / 100 * 100) / 100;
const totalGross = Math.round((totalNet + totalVat) * 100) / 100;

const events = [];

events.push({
  json: {
    event_type: 'invoice',
    batch_run_id: batchRunId,
    data: {
      invoice_key: invKey,
      supplier_key: supKey,
      supplier_name: invoice.supplier || '',
      invoice_number: invoice.invoice_id || '',
      invoice_date: invoice.purchase_date || new Date().toISOString().slice(0, 10),
      total_gross: totalGross,
      total_net: Math.round(totalNet * 100) / 100,
      vat_total: totalVat,
      source_pdf_path: invoice.drive_file_name || null,
      claude_extraction_json: invoice
    }
  }
});

lines.forEach((line, idx) => {
  const unitCost = Number(line.unit_cost) || 0;
  const qty = Number(line.quantity) || 1;
  events.push({
    json: {
      event_type: 'invoice_item',
      batch_run_id: batchRunId,
      data: {
        invoice_key: invKey,
        line_number: idx + 1,
        description_raw: line.source_item || line.nayax_product_name || '',
        quantity: qty,
        unit_price_net: unitCost,
        total_net: Math.round(unitCost * qty * 100) / 100,
        vat_rate_pct: Number(line.mwst_satz) || 7,
        mhd_date: line.mhd || null
      }
    }
  });
});

return events;
